import React from 'react';
import './index.scss';

import Templates from '../Templates/index';
import Button from '../Button/index';
import PersonalData from '../PersonalData';
import Education from '../Education';
import WorkExperience from '../WorkExperience';
import Languages from '../Languages';
import Download from '../Download';
import Skills from '../Skills';



export const changeStep = (currentStep, direction) => {
    const app = document.querySelector('.app__container');
    const property = direction === 'next' ? `translateX(-${currentStep + 1}00vw)` : `translateX(-${currentStep - 1}00vw)`;
    app.style.transform = property;
}

const Home = () => {
    
    const template = "";
    const personal = "";
    const schools = "";
    const works = "";
    const languages = "";
    const skills = "";

    return ( 
        <>
            <main className="home__container">
                <p className="hero__text">
                    Create your own CV with our templates!
                </p>
                <span onClick={() => changeStep(0, 'next')} >
                    <Button text="Start now" />
                </span>
                <p className="invite__text">
                    No programms needed.
                </p>
                <p className="invite__text">
                    Easy in use.
                </p>
                <p className="invite__text">
                    PDF format.
                </p>
            </main>
            <Templates />
            <PersonalData />
            <Education />
            <WorkExperience />
            <Languages />
            <Skills />
            <Download 
                template={template}
                personal={personal}
                schools={schools}
                works={works}
                languages={languages}
                skills={skills}
            />
        </>
    );
}
 
export default Home;
